import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"78. Workload Management","description":"","frontmatter":{"title":"78. Workload Management","eba":"Health Allied & Managers Admin 2021-2025","topics":["staffing","workload"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/classification-staffing/78-workload-management.md","filePath":"ebas/has-managers-admin/common-terms/classification-staffing/78-workload-management.md"}'),s={name:"ebas/has-managers-admin/common-terms/classification-staffing/78-workload-management.md"};function r(i,e,l,m,g,d){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_78-workload-management" tabindex="-1">78. Workload Management <a class="header-anchor" href="#_78-workload-management" aria-label="Permalink to &quot;78. Workload Management&quot;">​</a></h1><p><strong>78.1</strong> Staffing Levels</p><p><strong>(a)</strong> The parties recognise that adequate staffing levels promotes the maintenance of a working environment that is safe and free of risks to health, so far as is reasonably practicable.</p><p><strong>78.2</strong> Work-related Fatigue</p><p><strong>(a)</strong> The ‘WorkSafe Victoria - Work-related Fatigue: A Guide for Employers’ – is a suitable framework under which to consider work- related fatigue issues.</p><p><strong>78.3</strong> Assignment of Work</p><p><strong>(a)</strong> The Employer, when assigning work to an Employee, will consider matters including, but not limited to:</p><p><strong>(i)</strong> duties directly associated with the inherent requirements of the Employee’s role,</p><p><strong>(ii)</strong> duties not directly associated with the inherent requirements of the Employee’s role,</p><p><strong>(iii)</strong> consideration of workload where an Employee, in addition to their substantive duties, is assisting with local orientation and/or induction of new Employee(s) or students.</p><p><strong>(iv)</strong> consideration of workload where an absence has not been replaced on a shift,</p><p><strong>(v)</strong> the completion of mandatory training.</p><p><strong>78.4</strong> Raising Workload Management Concerns</p><p><strong>(a)</strong> Where an Employee believes that the Employer requires the Employee to perform work in a manner that is inconsistent with this Clause 78 - Workload Management, the Employee should raise the concerns with their immediate supervisor or line manager in the first instance and seek to resolve the issue.</p><p><strong>(b)</strong> If no resolution can be achieved, the Employee may:</p><p><strong>(i)</strong> utilise the Occupational Health &amp; Safety clause at <a href="/eba/ebas/has-managers-admin/common-terms/ohs/80-occupational-health-safety.html">clause 80</a> of this Agreement</p><p><strong>(ii)</strong> utilise the Dispute Resolution Procedure set out in <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a> of this Agreement.</p><p>Plain language terms: workload, reasonable workload.</p>',18)])])}const c=t(s,[["render",r]]);export{h as __pageData,c as default};
